        def _quantize(color_count):
            quantized_im = self._new(self.im.quantize(color_count, method, kmeans))
            mode = quantized_im.im.getpalettemode()
            quantized_im.palette = ImagePalette.ImagePalette(
                mode, quantized_im.im.getpalette(mode, mode)
            )
            return quantized_im

        if error_threshold is None or colors <= 1:
            return _quantize(colors)

        if error_threshold < 0:
            raise ValueError("error_threshold must be non-negative")

        from . import ImageChops, ImageStat

        reference_im = self.convert("RGB") if self.mode != "RGB" else self

        def _mean_square_error(quantized_im):
            diff = ImageChops.difference(reference_im, quantized_im.convert("RGB"))
            stat = ImageStat.Stat(diff)
            return sum(rms ** 2 for rms in stat.rms) / len(stat.rms)

        # Binary search for the smallest number of colors, up to the
        # requested limit, whose MSE is within the given error threshold.
        low, high = 1, colors
        best_im = None
        while low <= high:
            mid = (low + high) // 2
            candidate_im = _quantize(mid)
            if _mean_square_error(candidate_im) <= error_threshold:
                best_im = candidate_im
                high = mid - 1
            else:
                low = mid + 1

        return best_im if best_im is not None else _quantize(colors)"}

